"use client";

import { useState, useRef, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete, getRandomEncourage, triggerShake } from "@/lib/learningMessages";

interface Scene {
  id: string;
  emoji: string;
  title: string;
  question: string;
  options: { label: string; value: string; correct: boolean }[];
  answer: number;
  correctExplanation: string;
  answerAnimation: React.ReactNode;
}

const SCENES: Scene[] = [
  {
    id: "peach",
    emoji: "🍑",
    title: "分桃子",
    question: "小猴子摘了 45 个桃子，平均分给 5 只小猴子，每只分到几个？",
    options: [
      { label: "A", value: "45 ÷ 5", correct: true },
      { label: "B", value: "45 + 5", correct: false },
      { label: "C", value: "45 - 5", correct: false },
      { label: "D", value: "45 × 5", correct: false },
    ],
    answer: 9,
    correctExplanation: "45 ÷ 5 = 9，每只小猴子分到 9 个桃子！",
    answerAnimation: null as unknown as React.ReactNode,
  },
  {
    id: "flower",
    emoji: "🌸",
    title: "摆花盆",
    question: "学校买了 36 盆花，每个教室放 4 盆，可以分给几个教室？",
    options: [
      { label: "A", value: "36 ÷ 4", correct: true },
      { label: "B", value: "36 × 4", correct: false },
      { label: "C", value: "36 + 4", correct: false },
      { label: "D", value: "36 - 4", correct: false },
    ],
    answer: 9,
    correctExplanation: "36 ÷ 4 = 9，可以分给 9 个教室！",
    answerAnimation: null as unknown as React.ReactNode,
  },
  {
    id: "book",
    emoji: "📚",
    title: "分图书",
    question: "图书馆有 96 本故事书，平均放在 6 个书架上，每个书架放几本？",
    options: [
      { label: "A", value: "96 ÷ 6", correct: true },
      { label: "B", value: "96 + 6", correct: false },
      { label: "C", value: "96 - 6", correct: false },
      { label: "D", value: "96 × 6", correct: false },
    ],
    answer: 16,
    correctExplanation: "96 ÷ 6 = 16，每个书架放 16 本书！",
    answerAnimation: null as unknown as React.ReactNode,
  },
];

export default function ApplyPage() {
  const [sceneIndex, setSceneIndex] = useState(0);
  const [phase, setPhase] = useState<"select" | "answer" | "result">("select");
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [optionFeedback, setOptionFeedback] = useState<"idle" | "correct" | "wrong">("idle");
  const [inputValue, setInputValue] = useState("");
  const [answerFeedback, setAnswerFeedback] = useState<"idle" | "correct" | "wrong">("idle");
  const [showComplete, setShowComplete] = useState(false);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const optionAreaRef = useRef<HTMLDivElement>(null);
  const answerInputRef = useRef<HTMLInputElement>(null);

  const scene = SCENES[sceneIndex];
  const isLastScene = sceneIndex === SCENES.length - 1;

  // 选择算式
  const handleOptionSelect = (optionValue: string, isCorrect: boolean) => {
    if (optionFeedback === "correct") return; // 已经选对
    setSelectedOption(optionValue);
    if (isCorrect) {
      setOptionFeedback("correct");
      setPhase("answer");
    } else {
      setOptionFeedback("wrong");
      triggerShake(optionAreaRef.current);
      setTimeout(() => {
        setOptionFeedback("idle");
        setSelectedOption(null);
      }, 600);
    }
  };

  // 提交答案
  const handleAnswerSubmit = () => {
    const val = parseInt(inputValue.trim());
    if (val === scene.answer) {
      setAnswerFeedback("correct");
      setPhase("result");
    } else {
      setAnswerFeedback("wrong");
      triggerShake(answerInputRef.current);
      setInputValue("");
      setTimeout(() => {
        setAnswerFeedback("idle");
      }, 600);
    }
  };

  // 下一题
  const handleNextScene = () => {
    if (isLastScene) {
      setShowComplete(true);
    } else {
      setSceneIndex(sceneIndex + 1);
      setPhase("select");
      setSelectedOption(null);
      setOptionFeedback("idle");
      setInputValue("");
      setAnswerFeedback("idle");
    }
  };

  // 重新开始
  const handleRestart = () => {
    setSceneIndex(0);
    setPhase("select");
    setSelectedOption(null);
    setOptionFeedback("idle");
    setInputValue("");
    setAnswerFeedback("idle");
    setShowComplete(false);
  };

  return (
    <StepShell topicId="division" stepId="apply">
      <div className="space-y-5">
        {!showComplete ? (
          <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
            {/* 场景标题 */}
            <div className="text-center">
              <p className="text-sm font-bold text-[var(--accent)]">
                场景 {sceneIndex + 1} / {SCENES.length}
              </p>
              <h2 className="mt-1 text-xl font-bold text-[var(--text)]">
                {scene.emoji} {scene.title}
              </h2>
            </div>

            {/* SVG 场景插图 */}
            <div className="mt-5 flex justify-center">
              {scene.id === "peach" && <PeachTreeIllustration />}
              {scene.id === "flower" && <FlowerPotsIllustration />}
              {scene.id === "book" && <BookshelfIllustration />}
            </div>

            {/* 题目 */}
            <div className="mt-4 rounded-xl bg-[var(--bg-soft)] p-4">
              <p className="text-center text-sm text-[var(--text)]">
                {scene.question}
              </p>
            </div>

            {/* 步骤 1: 选择算式 */}
            {(phase === "select" || (phase === "answer" && optionFeedback === "correct")) && (
              <div className="mt-5">
                <p className="mb-3 text-center text-sm font-bold text-[var(--text-secondary)]">
                  步骤 1：选择正确的算式
                </p>
                <div ref={optionAreaRef} className="grid grid-cols-2 gap-2">
                  {scene.options.map((opt) => {
                    const isSelected = selectedOption === opt.value;
                    const isOptionCorrect = opt.correct && optionFeedback === "correct";
                    const isOptionWrong = isSelected && optionFeedback === "wrong";
                    return (
                      <button
                        key={opt.label}
                        onClick={() => handleOptionSelect(opt.value, opt.correct)}
                        className={`rounded-xl border-2 px-4 py-3 text-sm font-bold transition-all ${
                          isOptionCorrect
                            ? "border-[var(--signal-success)] bg-[var(--signal-success)]/20 text-[var(--signal-success)]"
                            : isOptionWrong
                              ? "border-[var(--accent)] bg-[var(--accent)]/10 text-[var(--accent)] animate-shake"
                              : "border-[var(--border)] bg-[var(--bg-card)] text-[var(--text)] hover:border-[var(--primary)]/50 hover:bg-[var(--primary)]/5"
                        }`}
                      >
                        <span className="mr-1 text-xs opacity-60">{opt.label}.</span>
                        {opt.value}
                        {isOptionCorrect && (
                          <span className="ml-2">✓</span>
                        )}
                      </button>
                    );
                  })}
                </div>
                {optionFeedback === "wrong" && (
                  <p className="mt-2 text-center text-sm text-[var(--text-muted)]">
                    {getRandomEncourage()}
                  </p>
                )}
              </div>
            )}

            {/* 步骤 2: 输入答案 */}
            {phase === "answer" && (
              <div className="mt-5">
                <p className="mb-3 text-center text-sm font-bold text-[var(--text-secondary)]">
                  步骤 2：算出答案
                </p>
                <div className="flex flex-col items-center gap-3">
                  <div className="flex items-center gap-2">
                    <span className="text-lg font-bold text-[var(--text)]">
                      {scene.options.find((o) => o.correct)!.value} =
                    </span>
                    <input
                      ref={answerInputRef}
                      type="number"
                      value={inputValue}
                      onChange={(e) => setInputValue(e.target.value)}
                      onKeyDown={(e) => e.key === "Enter" && handleAnswerSubmit()}
                      placeholder="?"
                      className="w-20 rounded-xl border-2 border-[var(--border)] bg-white px-4 py-2 text-center text-lg font-bold text-[var(--text)] outline-none transition-colors focus:border-[var(--primary)]"
                    />
                  </div>
                  <button
                    onClick={handleAnswerSubmit}
                    className="rounded-full bg-[var(--accent)] px-6 py-2.5 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    提交答案
                  </button>
                </div>

                {/* 答案反馈 */}
                {answerFeedback === "wrong" && (
                  <div className="mt-3 text-center text-sm text-[var(--text-muted)]">
                    {getRandomEncourage()}
                  </div>
                )}
              </div>
            )}

            {/* 结果展示 */}
            {phase === "result" && answerFeedback === "correct" && (
              <div className="mt-5 space-y-4">
                <div className="animate-float-in rounded-xl border-2 border-[var(--signal-success)] bg-[var(--signal-success)]/10 p-4 text-center">
                  <p className="font-bold text-[var(--signal-success)]">
                    {scene.correctExplanation}
                  </p>
                </div>

                {/* 分配动画 */}
                <div className="flex justify-center">
                  {scene.id === "peach" && <PeachAnimation />}
                  {scene.id === "flower" && <FlowerAnimation />}
                  {scene.id === "book" && <BookAnimation />}
                </div>

                {/* 下一题按钮 */}
                <div className="flex justify-center">
                  <button
                    onClick={handleNextScene}
                    className="animate-float-in rounded-full bg-[var(--accent)] px-8 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
                  >
                    {isLastScene ? "完成全部 →" : "下一题 →"}
                  </button>
                </div>
              </div>
            )}
          </section>
        ) : (
          /* 完成卡片 */
          <section className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">🎉</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              你已经会用除法解决生活中的问题啦！
            </p>

            {/* 总结 */}
            <div className="mx-auto mt-6 max-w-sm space-y-2">
              {SCENES.map((s) => (
                <div
                  key={s.id}
                  className="flex items-center justify-between rounded-lg bg-[var(--bg-soft)] px-4 py-2"
                >
                  <span className="text-sm text-[var(--text-secondary)]">
                    {s.emoji} {s.title}
                  </span>
                  <span className="text-sm font-bold text-[var(--text)]">
                    {s.options.find((o) => o.correct)!.value} = {s.answer}
                  </span>
                </div>
              ))}
            </div>

            <div className="mt-6 flex flex-wrap justify-center gap-3">
              <button
                onClick={handleRestart}
                className="rounded-full border border-[var(--border)] bg-[var(--bg-card)] px-5 py-2 text-sm font-medium text-[var(--text-secondary)] transition-colors hover:bg-[var(--bg-soft)]"
              >
                再做一次
              </button>
              <Link
                href="/learn/division"
                className="rounded-full bg-[var(--accent)] px-6 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5"
              >
                回到学习路径 →
              </Link>
            </div>
          </section>
        )}
      </div>
    </StepShell>
  );
}

