// ========== 场景 1 分配动画 ==========
function PeachAnimation() {
  return (
    <div className="flex flex-wrap justify-center gap-2 rounded-xl bg-[var(--bg-soft)] p-4">
      {Array.from({ length: 5 }).map((_, monkeyIdx) => (
        <div key={monkeyIdx} className="flex flex-col items-center gap-1">
          <div className="text-2xl animate-float-in" style={{ animationDelay: `${monkeyIdx * 200}ms` }}>
            🐵
          </div>
          <div className="flex gap-0.5">
            {Array.from({ length: 9 }).map((_, i) => (
              <span
                key={i}
                className="animate-float-in text-sm"
                style={{ animationDelay: `${monkeyIdx * 200 + i * 50}ms` }}
              >
                🍑
              </span>
            ))}
          </div>
          <span className="text-xs font-bold text-[var(--text-secondary)]">9 个</span>
        </div>
      ))}
    </div>
  );
}

