            {Array.from({ length: 4 }).map((_, i) => (
              <span
                key={i}
                className="animate-float-in text-sm"
                style={{ animationDelay: `${roomIdx * 100 + i * 40}ms` }}
              >
                🌸
              </span>
            ))}
