// ========== 场景 3 分配动画 ==========
function BookAnimation() {
  const booksPerShelf = 16;
  return (
    <div className="flex flex-wrap justify-center gap-3 rounded-xl bg-[var(--bg-soft)] p-4">
      {Array.from({ length: 6 }).map((_, shelfIdx) => (
        <div key={shelfIdx} className="flex flex-col items-center gap-1">
          <div
            className="flex gap-0.5"
            style={{ maxWidth: 80, flexWrap: "wrap" }}
          >
            {Array.from({ length: booksPerShelf }).map((_, i) => (
              <span
                key={i}
                className="animate-float-in text-xs"
                style={{ animationDelay: `${shelfIdx * 150 + i * 30}ms` }}
              >
                📕
              </span>
            ))}
          </div>
          <span className="text-xs font-bold text-[var(--text-secondary)]">
            第 {shelfIdx + 1} 层：{booksPerShelf} 本
          </span>
        </div>
      ))}
    </div>
  );
}
